from __future__ import annotations

import pytest

from orchestkit_hook_contract import (
    HOOK_EVENT_NAME_SET,
    HOOK_EVENT_NAMES,
    HOOK_EVENT_SCHEMA,
    HOOK_EVENT_SCHEMAS,
    HookEvent,
    is_hook_event,
    is_hook_event_name,
    validate_hook_event,
)


def test_19_known_event_names() -> None:
    assert len(HOOK_EVENT_NAMES) == 19
    assert "SessionStart" in HOOK_EVENT_NAMES
    assert "PreToolUse" in HOOK_EVENT_NAMES
    assert "WorktreeCreate" in HOOK_EVENT_NAMES


def test_name_set_matches_tuple() -> None:
    assert HOOK_EVENT_NAME_SET == frozenset(HOOK_EVENT_NAMES)
    assert len(HOOK_EVENT_NAME_SET) == 19


def test_aggregate_schema_oneof_19() -> None:
    assert isinstance(HOOK_EVENT_SCHEMA.get("oneOf"), list)
    assert len(HOOK_EVENT_SCHEMA["oneOf"]) == 19


@pytest.mark.parametrize("name", HOOK_EVENT_NAMES)
def test_each_event_has_schema(name: str) -> None:
    schema = HOOK_EVENT_SCHEMAS[name]
    assert schema["title"] == f"{name} hook event"
    assert schema["properties"]["event"]["const"] == name
    assert schema["required"] == ["event"]


def test_is_hook_event_name_known() -> None:
    assert is_hook_event_name("SessionStart") is True
    assert is_hook_event_name("PostToolUseFailure") is True


def test_is_hook_event_name_rejects_unknown() -> None:
    assert is_hook_event_name("SomethingElse") is False
    assert is_hook_event_name(42) is False
    assert is_hook_event_name(None) is False


def test_validate_minimal_envelope() -> None:
    result = validate_hook_event({"event": "SessionStart"})
    assert result.valid
    assert result.event == "SessionStart"  # type: ignore[union-attr]


def test_validate_full_envelope() -> None:
    result = validate_hook_event(
        {
            "event": "PreToolUse",
            "timestamp": "2026-05-18T10:11:16Z",
            "session_id": "sess_abc",
            "cwd": "/tmp/repo",
            "payload": {"tool_name": "Bash"},
        }
    )
    assert result.valid


def test_validate_rejects_non_object() -> None:
    assert not validate_hook_event(None).valid
    assert not validate_hook_event("SessionStart").valid
    assert not validate_hook_event([]).valid


def test_validate_rejects_missing_event() -> None:
    result = validate_hook_event({"timestamp": "now"})
    assert not result.valid
    assert any("missing required field: event" in e for e in result.errors)


def test_validate_rejects_unknown_event() -> None:
    result = validate_hook_event({"event": "NotAReal"})
    assert not result.valid
    assert any("unknown event tag" in e for e in result.errors)


def test_validate_rejects_malformed_optional() -> None:
    result = validate_hook_event({"event": "Stop", "timestamp": 12345})
    assert not result.valid


def test_is_hook_event_narrows() -> None:
    assert is_hook_event({"event": "WorktreeCreate"}) is True
    assert is_hook_event({"foo": "bar"}) is False


def test_hook_event_pydantic_envelope() -> None:
    """HookEvent BaseModel accepts the same payloads validate_hook_event does."""
    e = HookEvent(event="PreToolUse", payload={"tool_name": "Bash"})
    assert e.event == "PreToolUse"
    assert e.timestamp is None
    assert e.cwd is None
